// Pseudo-structure (to be implemented)
function generateRequestId(): string { /* uuid or similar */ }

async function retryFetch(
  url: string,
  options?: RequestInit,
  config?: { maxRetries?: number; baseDelay?: number }
): Promise<Response> {
  const requestId = generateRequestId();
  let lastError: Error | null = null;

  for (let attempt = 0; attempt <= (config?.maxRetries ?? 3); attempt++) {
    try {
      const response = await fetch(url, options);

      // C1: Don't retry on 4xx
      if (response.status >= 400 && response.status < 500) {
        return response;
      }

      if (response.ok) return response;

      // Retry on 5xx or network errors
      if (attempt < (config?.maxRetries ?? 3)) {
        const delay = (config?.baseDelay ?? 100) * Math.pow(2, attempt);
        logger.info(`Retry attempt ${attempt + 1}`, { requestId, delay });
        await sleep(delay);
      }
    } catch (error) {
      lastError = error as Error;
      if (attempt < (config?.maxRetries ?? 3)) {
        const delay = (config?.baseDelay ?? 100) * Math.pow(2, attempt);
        logger.info(`Retry attempt ${attempt + 1} after error`, { requestId, delay });
        await sleep(delay);
      }
    }
  }

  throw lastError || new Error(`Failed after retries`);
}
```

